<?php
namespace Ov\Component\Salaov\Administrator\Controller;
\defined('_JEXEC') or die;
use Joomla\CMS\MVC\Controller\BaseController; use Joomla\CMS\Factory;
class SlotsController extends BaseController { public function save(){ $app=Factory::getApplication(); $db=Factory::getContainer()->get('DatabaseDriver'); $id=$app->input->getInt('id'); $data=['title'=>$app->input->getString('title'),'weekday'=>$app->input->getInt('weekday'),'start_time'=>$app->input->getString('start_time').':00','end_time'=>$app->input->getString('end_time').':00','capacity'=>$app->input->getInt('capacity'),'published'=>$app->input->getInt('published',1)]; if($id){$sets=[]; foreach($data as $k=>$v){$sets[]=$db->quoteName($k).'='.$db->quote($v);} $q=$db->getQuery(true)->update('#__salaov_slots')->set($sets)->where('id='.(int)$id);} else {$cols=array_keys($data); $q=$db->getQuery(true)->insert('#__salaov_slots')->columns($db->quoteName($cols))->values(implode(',',array_map([$db,'quote'],array_values($data))));} $db->setQuery($q)->execute(); $this->setRedirect('index.php?option=com_salaov&view=slots','Fascia salvata'); } public function delete(){ $id=Factory::getApplication()->input->getInt('id'); if($id){$db=Factory::getContainer()->get('DatabaseDriver'); $db->setQuery('DELETE FROM #__salaov_slots WHERE id='.(int)$id)->execute();} $this->setRedirect('index.php?option=com_salaov&view=slots','Fascia eliminata'); }}
